Date: {{signature_date}}',
  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Company Email","description":"Company contact email","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Signatory Name","description":"Name of company signatory","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Company Address","description":"Company address","category":"party_a","type":"textarea","required":true,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Company Name","description":"Full company name","category":"party_a","type":"text","required":true,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Signatory Title","description":"Title of signatory","category":"party_a","type":"text","required":false,"autofillKey":"job_title"},{"id":"entity_type","token":"{{entity_type}}","label":"Entity Type","description":"Type of entity (corporation, LLC, etc.)","category":"party_a","type":"text","required":true},{"id":"party_b_email","token":"{{party_b_email}}","label":"Investor Email","description":"Investor email","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Investor Name","description":"Investor full legal name","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Investor Address","description":"Investor address","category":"party_b","type":"textarea","required":true},{"id":"effective_date","token":"{{effective_date}}","label":"Effective Date","description":"SAFE date","category":"dates","type":"date","required":true},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"venue_county","token":"{{venue_county}}","label":"Venue County","description":"Texas county for legal venue","category":"terms","type":"text","required":true},{"id":"investment_amount","token":"{{investment_amount}}","label":"Investment Amount","description":"Amount being invested","category":"financial","type":"currency","required":true},{"id":"valuation_cap","token":"{{valuation_cap}}","label":"Valuation Cap","description":"Maximum valuation for conversion","category":"financial","type":"currency","required":true},{"id":"discount_rate","token":"{{discount_rate}}","label":"Discount Rate","description":"Discount percentage (e.g., 20)","category":"financial","type":"number","required":true},{"id":"qualifying_round_threshold","token":"{{qualifying_round_threshold}}","label":"Qualifying Round Threshold","description":"Minimum amount for Equity Financing","category":"financial","type":"currency","required":true}]'::jsonb,
  true,
